if(!window.ColorBank){
(() => {
    'use strict'

    const encoder = new TextEncoder()
    const decoder = new TextDecoder()
    const pending = new Map()
    const peers = new Map()
    const sessions = new Map()
    const identities = new Map()
    const RATE_WINDOW_MS = 60000
    const RATE_MAX_ATTEMPTS = 5
    const RATE_LOCK_MS = 60000
    const KDF_ITERATIONS = 120000

    const utf8 = value => encoder.encode(String(value))
    const text = value => decoder.decode(value)
    const normalizeColor = value => String(value || '').replace('#', '').toLowerCase()
    const randomBytes = length => crypto.getRandomValues(new Uint8Array(length))
    const randomId = () => bytesToBase64Url(randomBytes(18))
    const privateRoom = app => normalizeColor(app.user?.color || localStorage.getItem('lastSphereColor') || 'ffffff')
    const vaultKey = instanceId => `local:bank-vault:${instanceId}`
    const deviceKey = accountId => `local:bank-device:${accountId}`
    const inboxKey = instanceId => `local:bank-inbox:${instanceId}`
    const guardianAccountsKey = 'local:bank-guardian-accounts-v1'
    const guardianRatesKey = 'local:bank-guardian-rates-v1'
    const guardianIdentityKey = 'local:bank-guardian-oprf-v1'
    const bankIndexKey = 'local:bank-index-v1'

    function concatBytes(...arrays) {
        const output = new Uint8Array(arrays.reduce((total, value) => total + value.length, 0))
        let offset = 0
        arrays.forEach(value => {
            output.set(value, offset)
            offset += value.length
        })
        return output
    }

    function bytesToBase64(bytes) {
        let binary = ''
        bytes.forEach(byte => binary += String.fromCharCode(byte))
        return btoa(binary)
    }

    function base64ToBytes(value) {
        const binary = atob(String(value || ''))
        return Uint8Array.from(binary, char => char.charCodeAt(0))
    }

    function bytesToBase64Url(bytes) {
        return bytesToBase64(bytes).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '')
    }

    function base64UrlToBytes(value) {
        let input = String(value || '').replace(/-/g, '+').replace(/_/g, '/')
        while (input.length % 4) input += '='
        return base64ToBytes(input)
    }

    async function sha256(bytes) {
        return new Uint8Array(await crypto.subtle.digest('SHA-256', bytes))
    }

    async function pbkdf2Pin(pin, salt) {
        const key = await crypto.subtle.importKey('raw', utf8(pin), 'PBKDF2', false, ['deriveBits'])
        return new Uint8Array(await crypto.subtle.deriveBits({
            name: 'PBKDF2',
            hash: 'SHA-256',
            salt,
            iterations: KDF_ITERATIONS
        }, key, 256))
    }

    async function hkdf(input, salt, info) {
        const key = await crypto.subtle.importKey('raw', input, 'HKDF', false, ['deriveBits'])
        return new Uint8Array(await crypto.subtle.deriveBits({
            name: 'HKDF',
            hash: 'SHA-256',
            salt,
            info: utf8(info)
        }, key, 256))
    }

    async function aesEncrypt(rawKey, plaintext, additionalData) {
        const key = await crypto.subtle.importKey('raw', rawKey, 'AES-GCM', false, ['encrypt'])
        const iv = randomBytes(12)
        const ciphertext = await crypto.subtle.encrypt({
            name: 'AES-GCM',
            iv,
            additionalData
        }, key, plaintext)
        return { iv: bytesToBase64(iv), ciphertext: bytesToBase64(new Uint8Array(ciphertext)) }
    }

    async function aesDecrypt(rawKey, packed, additionalData) {
        const key = await crypto.subtle.importKey('raw', rawKey, 'AES-GCM', false, ['decrypt'])
        return new Uint8Array(await crypto.subtle.decrypt({
            name: 'AES-GCM',
            iv: base64ToBytes(packed.iv),
            additionalData
        }, key, base64ToBytes(packed.ciphertext)))
    }

    async function readPrivate(app, key, fallback = null) {
        const raw = await app.identity._call('db_read_private', { roomHex: privateRoom(app), key }).catch(() => null)
        if (!raw || raw === '🔒' || raw === '--- CORRUPT ---') return fallback
        try {
            return JSON.parse(raw)
        } catch (error) {
            return fallback
        }
    }

    async function writePrivate(app, key, value) {
        await app.identity._call('db_write_private', {
            roomHex: privateRoom(app),
            key,
            value: JSON.stringify(value)
        })
    }

    function assertPin(pin) {
        if (!/^\d{4}$/.test(pin)) throw new Error('PIN must be exactly 4 digits.')
    }

    function gfMul(a, b) {
        let product = 0
        for (let i = 0; i < 8; i++) {
            if (b & 1) product ^= a
            const high = a & 0x80
            a = (a << 1) & 0xff
            if (high) a ^= 0x1b
            b >>= 1
        }
        return product
    }

    function gfPow(value, exponent) {
        let result = 1
        while (exponent > 0) {
            if (exponent & 1) result = gfMul(result, value)
            value = gfMul(value, value)
            exponent >>= 1
        }
        return result
    }

    const gfDiv = (a, b) => gfMul(a, gfPow(b, 254))

    function shamirSplit(secret, count, threshold) {
        const shares = Array.from({ length: count }, (_, index) => ({ x: index + 1, y: new Uint8Array(secret.length) }))
        for (let byteIndex = 0; byteIndex < secret.length; byteIndex++) {
            const coefficients = [secret[byteIndex]]
            for (let i = 1; i < threshold; i++) coefficients.push(randomBytes(1)[0])
            shares.forEach(share => {
                let value = coefficients[0]
                let xPower = 1
                for (let i = 1; i < coefficients.length; i++) {
                    xPower = gfMul(xPower, share.x)
                    value ^= gfMul(coefficients[i], xPower)
                }
                share.y[byteIndex] = value
            })
        }
        return shares
    }

    function shamirReconstruct(shares, length) {
        const output = new Uint8Array(length)
        for (let byteIndex = 0; byteIndex < length; byteIndex++) {
            let value = 0
            for (let i = 0; i < shares.length; i++) {
                let basis = 1
                for (let j = 0; j < shares.length; j++) {
                    if (i === j) continue
                    basis = gfMul(basis, gfDiv(shares[j].x, shares[i].x ^ shares[j].x))
                }
                value ^= gfMul(shares[i].y[byteIndex], basis)
            }
            output[byteIndex] = value
        }
        return output
    }

    function bytesToBigInt(bytes) {
        let hex = ''
        bytes.forEach(byte => hex += byte.toString(16).padStart(2, '0'))
        return BigInt(`0x${hex || '0'}`)
    }

    function bigIntToBytes(value, length) {
        let hex = value.toString(16)
        if (hex.length % 2) hex = `0${hex}`
        const raw = Uint8Array.from({ length: hex.length / 2 }, (_, index) => parseInt(hex.slice(index * 2, index * 2 + 2), 16))
        if (raw.length >= length) return raw.slice(raw.length - length)
        const output = new Uint8Array(length)
        output.set(raw, length - raw.length)
        return output
    }

    function modPow(base, exponent, modulus) {
        let result = 1n
        base %= modulus
        while (exponent > 0n) {
            if (exponent & 1n) result = result * base % modulus
            exponent >>= 1n
            base = base * base % modulus
        }
        return result
    }

    function gcd(a, b) {
        while (b !== 0n) [a, b] = [b, a % b]
        return a
    }

    function modInverse(value, modulus) {
        let oldR = value % modulus
        let r = modulus
        let oldS = 1n
        let s = 0n
        while (r !== 0n) {
            const quotient = oldR / r
            ;[oldR, r] = [r, oldR - quotient * r]
            ;[oldS, s] = [s, oldS - quotient * s]
        }
        if (oldR !== 1n) throw new Error('Invalid guardian key.')
        return (oldS % modulus + modulus) % modulus
    }

    function randomBigIntBelow(max) {
        const length = Math.ceil(max.toString(2).length / 8)
        while (true) {
            const value = bytesToBigInt(randomBytes(length))
            if (value > 1n && value < max) return value
        }
    }

    function rsaNumbers(jwk) {
        const modulus = base64UrlToBytes(jwk.n)
        return {
            n: bytesToBigInt(modulus),
            e: bytesToBigInt(base64UrlToBytes(jwk.e)),
            d: jwk.d ? bytesToBigInt(base64UrlToBytes(jwk.d)) : null,
            length: modulus.length
        }
    }

    async function ensureGuardianIdentity(app) {
        const color = privateRoom(app)
        if (identities.has(color)) return identities.get(color)
        let privateJwk = await readPrivate(app, guardianIdentityKey)
        if (!privateJwk?.n || !privateJwk?.e || !privateJwk?.d) {
            const keyPair = await crypto.subtle.generateKey({
                name: 'RSA-PSS',
                modulusLength: 2048,
                publicExponent: new Uint8Array([1, 0, 1]),
                hash: 'SHA-256'
            }, true, ['sign', 'verify'])
            const exported = await crypto.subtle.exportKey('jwk', keyPair.privateKey)
            privateJwk = { n: exported.n, e: exported.e, d: exported.d }
            await writePrivate(app, guardianIdentityKey, privateJwk)
        }
        const fingerprint = bytesToBase64Url(await sha256(utf8(`${privateJwk.n}.${privateJwk.e}`))).slice(0, 14)
        const identity = { privateJwk, publicJwk: { n: privateJwk.n, e: privateJwk.e, fp: fingerprint } }
        identities.set(color, identity)
        return identity
    }

    async function makeBlind(pin, accountId, guardianId, handle, publicJwk) {
        const publicNumbers = rsaNumbers(publicJwk)
        const input = concatBytes(
            utf8('color-bank-oprf-input-v1|'),
            utf8(accountId),
            utf8('|'),
            utf8(guardianId),
            utf8('|'),
            utf8(handle),
            utf8('|'),
            utf8(pin)
        )
        let message = bytesToBigInt(await sha256(input)) % (publicNumbers.n - 1n)
        if (message < 2n) message += 2n
        while (gcd(message, publicNumbers.n) !== 1n) message += 1n
        let blinder
        do {
            blinder = randomBigIntBelow(publicNumbers.n - 1n)
        } while (gcd(blinder, publicNumbers.n) !== 1n)
        return {
            blinded: bytesToBase64(bigIntToBytes(message * modPow(blinder, publicNumbers.e, publicNumbers.n) % publicNumbers.n, publicNumbers.length)),
            blinder,
            modulus: publicNumbers.n,
            length: publicNumbers.length
        }
    }

    async function unblind(signed, blind) {
        const value = bytesToBigInt(base64ToBytes(signed)) * modInverse(blind.blinder, blind.modulus) % blind.modulus
        return sha256(concatBytes(utf8('color-bank-oprf-output-v1|'), bigIntToBytes(value, blind.length)))
    }

    async function signBlinded(app, blinded) {
        const identity = await ensureGuardianIdentity(app)
        const numbers = rsaNumbers(identity.privateJwk)
        const value = bytesToBigInt(base64ToBytes(blinded)) % numbers.n
        return bytesToBase64(bigIntToBytes(modPow(value, numbers.d, numbers.n), numbers.length))
    }

    async function shareWrapKey(oprfOutput, accountId, guardianId, handle) {
        return hkdf(
            oprfOutput,
            await sha256(utf8(`share-wrap-salt|${accountId}|${guardianId}|${handle}`)),
            `share-wrap-key|${accountId}|${guardianId}|${handle}`
        )
    }

    async function vaultKeyEncryptionKey(pin, salt, deviceSecret, peerSecret, accountId) {
        return hkdf(
            concatBytes(await pbkdf2Pin(pin, salt), deviceSecret, peerSecret),
            await sha256(utf8(`vault-kek-salt|${accountId}`)),
            `vault-kek|${accountId}`
        )
    }

    async function rateLimit(app, key, charge) {
        const rates = await readPrivate(app, guardianRatesKey, {})
        const now = Date.now()
        const rate = rates[key] || { windowStart: now, count: 0, lockedUntil: 0 }
        if (rate.lockedUntil && now < rate.lockedUntil) throw new Error(`Locked for ${Math.ceil((rate.lockedUntil - now) / 1000)} seconds.`)
        if (now - rate.windowStart > RATE_WINDOW_MS) Object.assign(rate, { windowStart: now, count: 0, lockedUntil: 0 })
        if (rate.count >= RATE_MAX_ATTEMPTS) {
            rate.lockedUntil = now + RATE_LOCK_MS
            rates[key] = rate
            await writePrivate(app, guardianRatesKey, rates)
            throw new Error('Too many PIN attempts. Try again in 60 seconds.')
        }
        if (charge) rate.count += 1
        rates[key] = rate
        await writePrivate(app, guardianRatesKey, rates)
        return rate
    }

    async function handleOprfRequest(app, request) {
        if (!request?.accountId || !request?.handle || !request?.blinded || !request?.purpose) throw new Error('Malformed unlock request.')
        const guardianId = normalizeColor(request.guardianId)
        if (guardianId !== privateRoom(app)) throw new Error('Wrong guardian.')
        const accounts = await readPrivate(app, guardianAccountsKey, {})
        const account = accounts[request.accountId]
        if (request.purpose !== 'setup') {
            if (!account || account.handle !== request.handle) throw new Error('This device does not hold that bank share.')
        }
        const rate = await rateLimit(app, `${request.accountId}:${request.handle}`, request.purpose !== 'setup')
        return {
            ok: true,
            signed: await signBlinded(app, request.blinded),
            encryptedShare: account?.encryptedShare || null,
            x: account?.x || null,
            rate: { count: rate.count, max: RATE_MAX_ATTEMPTS }
        }
    }

    async function provisionGuardian(app, payload) {
        if (!payload?.accountId || !payload?.handle || !payload?.encryptedShare || !payload?.x) throw new Error('Malformed guardian share.')
        if (normalizeColor(payload.guardianId) !== privateRoom(app)) throw new Error('Wrong guardian.')
        const accounts = await readPrivate(app, guardianAccountsKey, {})
        accounts[payload.accountId] = {
            accountId: payload.accountId,
            handle: payload.handle,
            x: payload.x,
            encryptedShare: payload.encryptedShare,
            threshold: payload.threshold,
            coordinatorColor: payload.coordinatorColor,
            created: Date.now()
        }
        await writePrivate(app, guardianAccountsKey, accounts)
        return { ok: true }
    }

    function peerBucket(instanceId) {
        if (!peers.has(instanceId)) peers.set(instanceId, new Map())
        return peers.get(instanceId)
    }

    function availableGuardians(app, instanceId) {
        const connected = new Set(Object.entries(app.mesh?.getPeers?.() || {}).filter(([, peer]) => peer?.dc?.readyState === 'open').map(([pid]) => pid))
        const now = Date.now()
        return Array.from(peerBucket(instanceId).values()).filter(peer => peer.publicJwk?.n && connected.has(peer.pid) && now - peer.seen < 45000)
    }

    function sendRequest(app, type, payload, targetPeer, timeout = 12000) {
        const requestId = randomId()
        return new Promise((resolve, reject) => {
            const timer = setTimeout(() => {
                pending.delete(requestId)
                reject(new Error('Guardian did not respond.'))
            }, timeout)
            pending.set(requestId, { resolve, reject, timer })
            app.mesh?.sendBlockAction?.('bank_ops', { type, requestId, ...payload }, targetPeer)
        })
    }

    function resolveRequest(message) {
        const item = pending.get(message.responseTo)
        if (!item) return false
        clearTimeout(item.timer)
        pending.delete(message.responseTo)
        if (message.ok === false) item.reject(new Error(message.error || 'Bank request failed.'))
        else item.resolve(message)
        return true
    }

    async function saveSession(app, session) {
        session.record.vaultCiphertext = await aesEncrypt(
            session.dek,
            utf8(JSON.stringify(session.ledger)),
            utf8(`vault|${session.record.accountId}`)
        )
        await writePrivate(app, vaultKey(session.instanceId), session.record)
    }

    function dummyLedger() {
        const now = Date.now()
        return {
            balance: 1250,
            currency: 'USD',
            transactions: [
                { id: randomId(), title: 'Opening balance', amount: 1000, created: now - 86400000 * 8 },
                { id: randomId(), title: 'Color transfer', amount: 300, created: now - 86400000 * 3 },
                { id: randomId(), title: 'Coffee', amount: -50, created: now - 86400000 }
            ]
        }
    }

    async function createVault(app, instanceId, pin) {
        assertPin(pin)
        if (!crypto.subtle) throw new Error('WebCrypto is required.')
        const remoteGuardians = availableGuardians(app, instanceId)
        if (!remoteGuardians.length) throw new Error('Connect one Color device with QR before setting your PIN.')
        const localIdentity = await ensureGuardianIdentity(app)
        const localColor = privateRoom(app)
        const guardians = [
            { guardianId: localColor, name: 'This device', publicJwk: localIdentity.publicJwk, local: true },
            ...remoteGuardians.map(peer => ({ guardianId: peer.guardianId, name: peer.name || `#${peer.guardianId}`, publicJwk: peer.publicJwk, pid: peer.pid }))
        ]
        const accountId = randomId()
        const salt = randomBytes(16)
        const dek = randomBytes(32)
        const deviceSecret = randomBytes(32)
        const peerSecret = randomBytes(32)
        const threshold = 2
        const shares = shamirSplit(peerSecret, guardians.length, threshold)
        const committee = []

        for (let index = 0; index < guardians.length; index++) {
            const guardian = guardians[index]
            const share = shares[index]
            const handle = randomId()
            const blind = await makeBlind(pin, accountId, guardian.guardianId, handle, guardian.publicJwk)
            const response = guardian.local
                ? await handleOprfRequest(app, { purpose: 'setup', accountId, guardianId: guardian.guardianId, handle, blinded: blind.blinded })
                : await sendRequest(app, 'OPRF_REQUEST', { blockInstanceId: instanceId, purpose: 'setup', accountId, guardianId: guardian.guardianId, handle, blinded: blind.blinded }, guardian.pid)
            const wrapKey = await shareWrapKey(await unblind(response.signed, blind), accountId, guardian.guardianId, handle)
            const encryptedShare = await aesEncrypt(
                wrapKey,
                share.y,
                utf8(`encrypted-share|${accountId}|${guardian.guardianId}|${handle}|${share.x}`)
            )
            const provision = {
                blockInstanceId: instanceId,
                accountId,
                guardianId: guardian.guardianId,
                handle,
                x: share.x,
                encryptedShare,
                threshold,
                coordinatorColor: localColor
            }
            if (guardian.local) await provisionGuardian(app, provision)
            else await sendRequest(app, 'PROVISION', provision, guardian.pid)
            committee.push({
                guardianId: guardian.guardianId,
                name: guardian.name,
                handle,
                x: share.x,
                publicJwk: guardian.publicJwk,
                local: !!guardian.local
            })
        }

        const keyEncryptionKey = await vaultKeyEncryptionKey(pin, salt, deviceSecret, peerSecret, accountId)
        const ledger = dummyLedger()
        const record = {
            version: 1,
            accountId,
            created: Date.now(),
            kdf: { name: 'PBKDF2-SHA256', iterations: KDF_ITERATIONS, salt: bytesToBase64(salt) },
            threshold: { k: threshold, n: guardians.length },
            committee,
            wrappedDEK: await aesEncrypt(keyEncryptionKey, dek, utf8(`wrapped-dek|${accountId}`)),
            vaultCiphertext: await aesEncrypt(dek, utf8(JSON.stringify(ledger)), utf8(`vault|${accountId}`))
        }
        await writePrivate(app, vaultKey(instanceId), record)
        await writePrivate(app, deviceKey(accountId), { deviceSecret: bytesToBase64(deviceSecret) })
        await writePrivate(app, bankIndexKey, { instanceId, accountId })
        sessions.set(instanceId, { instanceId, ownerColor: localColor, record, ledger, dek })
        window.dispatchEvent(new CustomEvent('color-bank-update', { detail: { instanceId } }))
        return ledger
    }

    async function unlockVault(app, instanceId, pin) {
        assertPin(pin)
        const record = await readPrivate(app, vaultKey(instanceId))
        if (!record) throw new Error('Set your PIN first.')
        const device = await readPrivate(app, deviceKey(record.accountId))
        if (!device?.deviceSecret) throw new Error('This bank is missing its device factor.')
        const connected = new Map(availableGuardians(app, instanceId).map(peer => [peer.guardianId, peer]))
        const recovered = []

        for (const guardian of record.committee) {
            if (recovered.length >= record.threshold.k) break
            try {
                const blind = await makeBlind(pin, record.accountId, guardian.guardianId, guardian.handle, guardian.publicJwk)
                const response = guardian.local
                    ? await handleOprfRequest(app, { purpose: 'unlock', accountId: record.accountId, guardianId: guardian.guardianId, handle: guardian.handle, blinded: blind.blinded })
                    : connected.has(guardian.guardianId)
                        ? await sendRequest(app, 'OPRF_REQUEST', { blockInstanceId: instanceId, purpose: 'unlock', accountId: record.accountId, guardianId: guardian.guardianId, handle: guardian.handle, blinded: blind.blinded }, connected.get(guardian.guardianId).pid)
                        : null
                if (!response?.encryptedShare) continue
                const wrapKey = await shareWrapKey(await unblind(response.signed, blind), record.accountId, guardian.guardianId, guardian.handle)
                recovered.push({
                    x: guardian.x,
                    y: await aesDecrypt(
                        wrapKey,
                        response.encryptedShare,
                        utf8(`encrypted-share|${record.accountId}|${guardian.guardianId}|${guardian.handle}|${guardian.x}`)
                    )
                })
            } catch (error) { }
        }

        if (recovered.length < record.threshold.k) throw new Error('Wrong PIN, guardian offline, or rate limit reached.')
        const peerSecret = shamirReconstruct(recovered.slice(0, record.threshold.k), 32)
        const keyEncryptionKey = await vaultKeyEncryptionKey(pin, base64ToBytes(record.kdf.salt), base64ToBytes(device.deviceSecret), peerSecret, record.accountId)
        const dek = await aesDecrypt(keyEncryptionKey, record.wrappedDEK, utf8(`wrapped-dek|${record.accountId}`))
        const ledger = JSON.parse(text(await aesDecrypt(dek, record.vaultCiphertext, utf8(`vault|${record.accountId}`))))
        const inbox = await readPrivate(app, inboxKey(instanceId), [])
        const existing = new Set((ledger.transactions || []).map(item => item.id))
        inbox.filter(item => !existing.has(item.id)).forEach(item => {
            ledger.transactions.unshift(item)
            ledger.balance = Number((Number(ledger.balance || 0) + Number(item.amount || 0)).toFixed(2))
        })
        const session = { instanceId, ownerColor: privateRoom(app), record, ledger, dek }
        sessions.set(instanceId, session)
        if (inbox.length) {
            await saveSession(app, session)
            await writePrivate(app, inboxKey(instanceId), [])
        }
        window.dispatchEvent(new CustomEvent('color-bank-update', { detail: { instanceId } }))
        return ledger
    }

    function activeSession(app) {
        const color = privateRoom(app)
        return Array.from(sessions.values()).reverse().find(session => session.ownerColor === color) || null
    }

    function ownerPeerId(app) {
        const roomColor = normalizeColor(app.roomId?.replace('color-', ''))
        for (const [pid, identity] of app.mesh?.peerIdentities || []) {
            if (normalizeColor(identity?.color) === roomColor) return pid
        }
        const connected = Object.entries(app.mesh?.getPeers?.() || {}).filter(([, peer]) => peer?.dc?.readyState === 'open')
        return connected.length === 1 ? connected[0][0] : null
    }

    async function sendPayment(app, blockInstanceId, amount) {
        const session = activeSession(app)
        if (!session) throw new Error('Open your bank before connecting.')
        const value = Number(Number(amount).toFixed(2))
        if (!Number.isFinite(value) || value <= 0 || value > 1000000) throw new Error('Enter a valid amount.')
        if (Number(session.ledger.balance || 0) < value) throw new Error('Not enough fake money.')
        const paymentId = randomId()
        const result = await sendRequest(app, 'PAYMENT', {
            blockInstanceId,
            paymentId,
            amount: value,
            fromColor: app.user.color
        }, ownerPeerId(app))
        session.ledger.balance = Number((Number(session.ledger.balance || 0) - value).toFixed(2))
        session.ledger.transactions.unshift({
            id: paymentId,
            title: `Sent to #${normalizeColor(app.roomId?.replace('color-', '')).slice(0, 6)}`,
            amount: -value,
            created: Date.now()
        })
        await saveSession(app, session)
        return result
    }

    async function receivePayment(app, message, pid) {
        const roomColor = normalizeColor(app.roomId?.replace('color-', ''))
        if (roomColor !== privateRoom(app)) throw new Error('Only the bank owner can receive payments.')
        const block = app.getBlockPayloadByInstance(message.blockInstanceId)
        if (!block || block.blockId !== 'bank') throw new Error('Bank not found.')
        const amount = Number(Number(message.amount).toFixed(2))
        if (!message.paymentId || !Number.isFinite(amount) || amount <= 0 || amount > 1000000) throw new Error('Invalid payment.')
        const senderColor = normalizeColor(app.peerColors?.[pid] || message.fromColor)
        const transaction = {
            id: message.paymentId,
            title: `Received from #${senderColor.slice(0, 6) || 'guest'}`,
            amount,
            created: Date.now()
        }
        const session = sessions.get(message.blockInstanceId)
        if (session) {
            if (!session.ledger.transactions.some(item => item.id === transaction.id)) {
                session.ledger.transactions.unshift(transaction)
                session.ledger.balance = Number((Number(session.ledger.balance || 0) + amount).toFixed(2))
                await saveSession(app, session)
            }
        } else {
            const inbox = await readPrivate(app, inboxKey(message.blockInstanceId), [])
            if (!inbox.some(item => item.id === transaction.id)) {
                inbox.unshift(transaction)
                await writePrivate(app, inboxKey(message.blockInstanceId), inbox.slice(0, 100))
            }
        }
        window.dispatchEvent(new CustomEvent('color-bank-update', { detail: { instanceId: message.blockInstanceId } }))
        return { ok: true, receipt: transaction.id }
    }

    async function handleAction(context) {
        const { app, data, pid, send } = context
        if (!data?.type) return
        if (data.type === 'RESPONSE') {
            resolveRequest(data)
            return
        }
        if (data.type === 'HELLO') {
            const guardianId = normalizeColor(data.guardianId)
            if (!guardianId || !data.publicJwk?.n || !data.blockInstanceId) return
            peerBucket(data.blockInstanceId).set(guardianId, {
                pid,
                guardianId,
                name: data.name || `#${guardianId}`,
                publicJwk: data.publicJwk,
                seen: Date.now()
            })
            window.dispatchEvent(new CustomEvent('color-bank-update', { detail: { instanceId: data.blockInstanceId } }))
            return
        }
        try {
            let result
            if (data.type === 'OPRF_REQUEST') result = await handleOprfRequest(app, data)
            else if (data.type === 'PROVISION') result = await provisionGuardian(app, data)
            else if (data.type === 'PAYMENT') result = await receivePayment(app, data, pid)
            else return
            send({ type: 'RESPONSE', responseTo: data.requestId, ...result }, pid)
        } catch (error) {
            send({ type: 'RESPONSE', responseTo: data.requestId, ok: false, error: error.message || String(error) }, pid)
        }
    }

    function hydrate(context) {
        const { app, root, payload, isAdmin, escapeHtml } = context
        root.__colorBank?.destroy?.()
        const line = root.closest('.editor-line')
        if (line) {
            line.style.paddingLeft = '0'
            line.style.borderLeft = '0'
            line.style.minHeight = '100vh'
        }
        const cleanups = []
        const on = (target, event, listener) => {
            target?.addEventListener(event, listener)
            cleanups.push(() => target?.removeEventListener(event, listener))
        }
        const status = root.querySelector('[data-bank-status]')
        const setStatus = (message, error = false) => {
            if (!status) return
            status.textContent = message
            status.classList.toggle('error', error)
        }

        if (isAdmin) {
            const auth = root.querySelector('[data-bank-auth]')
            const account = root.querySelector('[data-bank-account]')
            const input = root.querySelector('[data-bank-pin]')
            const submit = root.querySelector('[data-bank-submit]')
            let pin = ''
            let hasVault = false

            const renderAccount = () => {
                const session = sessions.get(payload.instanceId)
                auth.hidden = !!session
                account.hidden = !session
                if (!session) return
                root.querySelector('[data-bank-balance]').textContent = new Intl.NumberFormat('en-US', { style: 'currency', currency: session.ledger.currency || 'USD' }).format(session.ledger.balance || 0)
                root.querySelector('[data-bank-transactions]').innerHTML = (session.ledger.transactions || []).slice(0, 20).map(item => `
                    <div class="bank-transaction">
                        <div><b>${escapeHtml(item.title || 'Transaction')}</b><span>${escapeHtml(new Date(item.created || Date.now()).toLocaleDateString())}</span></div>
                        <strong class="${Number(item.amount) < 0 ? 'debit' : ''}">${Number(item.amount) < 0 ? '-' : '+'}${escapeHtml(Math.abs(Number(item.amount || 0)).toFixed(2))}</strong>
                    </div>
                `).join('')
            }

            const renderAuth = () => {
                input.value = pin
                submit.textContent = hasVault ? 'OPEN' : 'SET PIN'
                const count = availableGuardians(app, payload.instanceId).length
                if (!hasVault) setStatus(count ? '1 COLOR GUARDIAN CONNECTED' : 'CONNECT ONE COLOR DEVICE WITH QR')
            }

            root.querySelectorAll('[data-bank-key]').forEach(button => on(button, 'click', () => {
                const key = button.dataset.bankKey
                if (key === 'back') pin = pin.slice(0, -1)
                else if (key === 'clear') pin = ''
                else if (pin.length < 4) pin += key
                renderAuth()
            }))

            on(submit, 'click', async () => {
                submit.disabled = true
                setStatus(hasVault ? 'OPENING...' : 'SECURING BANK...')
                try {
                    if (hasVault) await unlockVault(app, payload.instanceId, pin)
                    else {
                        await createVault(app, payload.instanceId, pin)
                        hasVault = true
                    }
                    pin = ''
                    renderAccount()
                } catch (error) {
                    setStatus(error.message || String(error), true)
                } finally {
                    submit.disabled = false
                    renderAuth()
                }
            })

            on(root.querySelector('[data-bank-connect]'), 'click', () => app.enterFullPeek?.('qr'))
            on(root.querySelector('[data-bank-lock]'), 'click', () => {
                sessions.delete(payload.instanceId)
                pin = ''
                renderAccount()
                renderAuth()
            })
            const update = event => {
                if (!event.detail?.instanceId || event.detail.instanceId === payload.instanceId) {
                    renderAccount()
                    renderAuth()
                }
            }
            on(window, 'color-bank-update', update)
            const timer = setInterval(renderAuth, 5000)
            cleanups.push(() => clearInterval(timer))
            ensureGuardianIdentity(app).catch(error => setStatus(error.message || String(error), true))
            readPrivate(app, vaultKey(payload.instanceId)).then(record => {
                hasVault = !!record
                renderAccount()
                renderAuth()
            })
        } else {
            const amount = root.querySelector('[data-bank-amount]')
            const submit = root.querySelector('[data-bank-pay]')
            const sendHello = async () => {
                if (!root.isConnected) return
                const identity = await ensureGuardianIdentity(app)
                context.send({
                    type: 'HELLO',
                    blockInstanceId: payload.instanceId,
                    guardianId: privateRoom(app),
                    name: `#${privateRoom(app).slice(0, 6)}`,
                    publicJwk: identity.publicJwk
                })
            }
            on(submit, 'click', async () => {
                submit.disabled = true
                setStatus('SENDING...')
                try {
                    const result = await sendPayment(app, payload.instanceId, amount.value)
                    amount.value = ''
                    setStatus(`SENT · ${String(result.receipt || '').slice(0, 10)}`)
                } catch (error) {
                    setStatus(error.message || String(error), true)
                } finally {
                    submit.disabled = false
                }
            })
            setStatus(activeSession(app) ? 'BANK CONNECTED' : 'OPEN YOUR BANK BEFORE CONNECTING')
            sendHello().catch(error => setStatus(error.message || String(error), true))
            const timer = setInterval(() => sendHello().catch(() => { }), 15000)
            cleanups.push(() => clearInterval(timer))
        }

        root.__colorBank = { destroy: () => cleanups.splice(0).forEach(cleanup => cleanup()) }
    }

    window.ColorBank = { hydrate, handleAction }
})()
}
if(context.pid&&context.data?.type)await window.ColorBank.handleAction(context);
